export function recruiterOutreach(track, settings) {
    return `Olá, tudo bem? Me chamo ${settings.profile.name}. Tenho mais de 12 anos de experiência em hospitalidade, coquetelaria, atendimento ao cliente, eventos e gestão de operação de bar. Gostaria de me colocar à disposição para oportunidades compatíveis com ${track}. Segue meu currículo para avaliação.`;
}
